            except IndexError:  # Nothing to serialize
                return dict((k, v) for k, v in self.declared_fields.items() if k in field_names)
        ret = self.dict_class()
        for key in field_names:
            if key in self.declared_fields:
                ret[key] = self.declared_fields[key]
